-- Store a German translation of the methodology text for the DE UI language.
alter table public.valuation_assumptions
  add column if not exists methodology_de text;

update public.valuation_assumptions
  set methodology_de = 'Indikativer Unternehmenswert, abgeleitet durch Anwendung beobachteter EV/EBITDA- oder EV/Umsatz-Multiplikatoren — aus einem Screening von 16 börsennotierten Personaldienstleistungs- und HR-Vergleichsunternehmen und 8 Präzedenztransaktionen — auf Michelscoms GJ2026E-EBITDA (2,6 Mio. €) bzw. -Umsatz (7,0 Mio. €), je nach gewähltem Multiplikator. Szenarien sind definiert als: Niedrig = unteres Quartil, Median & Durchschnitt = Basisszenario, Aufwärts = Mittelwert aus oberem Quartil und Maximum, Max = höchster beobachteter Multiplikator. Eine optionale Größenanpassung reduziert nur die Multiplikatoren von Größenausreißern — jene, deren EBITDA außerhalb von etwa einem Drittel bis dem Dreifachen desjenigen von Michelscom liegt —, um die Größe des Zielunternehmens besser abzubilden; Vergleichsunternehmen ähnlicher Größe bleiben unangepasst. Quartile werden auf den jeweiligen (angepassten) Multiplikatorsätzen berechnet; der gemischte Wert entspricht dem einfachen Durchschnitt der beiden Methoden, sofern nicht neu gewichtet wird. Die Zahlen sind indikativ, auf eine Nachkommastelle gerundet, auf einer cash- und schuldenfreien Unternehmenswert-Basis dargestellt (keine Nettoverschuldungsbrücke zum Eigenkapitalwert) und stellen keine Fairness Opinion oder formale Bewertung dar. Peer-Multiplikatoren aus öffentlichen GJ2025-Abschlüssen; Transaktionsmultiplikatoren aus veröffentlichten Deal-Daten. Erstellt von atares ausschließlich zu Diskussionszwecken.'
  where id = 1;
